var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이런 멍청한 것들……! 그런 꼬마들에게 포위망을 뚫리다니 제정신이냐?!","JPN":"この愚か者め……！　あのようなガキ共に包囲網を破られるとは！？","ENG":"You bumbling idiots...! You let those brats get away?! Are you out of your minds?!","TWN":"你們這些愚蠢的東西……！竟然被那種小鬼給突破包圍網？！有沒有搞錯！！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_C_NULL","text":{"KOREA":"죄송합니다, 대장님! 남자애 쪽이 생긴 것과 다르게 재빨라서 그만……!","JPN":"申し訳ありません、隊長！　男の子が見た目とは違い、すばしこく……！","ENG":"Sorry, captain! That boy was faster than he looked...!","TWN":"隊長抱歉！沒想到那男孩動作那麼快……！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_C_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_C_NULL","text":{"KOREA":"컥……?!","JPN":"ぐはっ……！？","ENG":"Kuh...!","TWN":"唔……？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_C_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그 따위 변명 집어치워라!","JPN":"言い訳なんぞ聞きたくない！","ENG":"Don’t give me excuses!","TWN":"還有臉解釋！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"잘 들어라. 이건 제국의 안위가 걸린 문제다.","JPN":"よく聞け。これは帝国の安寧がかかっている問題だ。","ENG":"Listen carefully. The safety of the empire is at stake.","TWN":"全都給我聽著，這可是關係到帝國的安危！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"도난품을 회수하지 못하면 우리 목이 달아난단 말이다. 알겠나?","JPN":"盗難品を回収できなければ、俺たちの首が文字どおり飛ぶんだ。わかったか？","ENG":"It’ll be our necks under the executioner’s axe if we don’t get back the stolen item. Do you understand?!","TWN":"要是東西拿不回來，我們全都人頭不保，明白嗎！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_C_NULL","text":{"KOREA":"며, 명심하겠습니다!","JPN":"り、了解いたしました！","ENG":"Y-yes, sir!","TWN":"是…明白！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_C_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흩어져서 샅샅이 찾아! 전령을 보내서 다른 부대들에게도 상황을 전파하도록!","JPN":"散開して隈なく探せ！　伝令で他の部隊にも状況を伝えるように！","ENG":"Spread out and search every nook and cranny! Dispatch messengers to the other units and notify them of the situation!","TWN":"分頭去搜！傳令下去，讓其他部隊也知道這個情況！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"휴우…… 간신히 따돌렸나 봐.","JPN":"ふう……どうにか撒けたみたいだね。","ENG":"Phew... We barely threw them off of our trail.","TWN":"呼……好像終於甩掉他們了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"하아……. 하아……. 하아…….","JPN":"はあ……はあ……はあ……","ENG":"*Huff... Huff... Huff…*","TWN":"呼呼……呼呼……呼呼……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"천천히 심호흡해. 기사들이 하수도까지는 쫓아오지 않을 거야.","JPN":"ゆっくり深呼吸して。騎士は下水道まではたぶん追ってこないよ。","ENG":"Take slow, deep breaths. The knights won’t chase us all the way into the sewers.","TWN":"慢慢深呼吸，那些騎士應該不會追到下水道來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그나저나 센트럴 팰리스는 하수도도 정말 크네. 대단하다.","JPN":"それよりセントラルパレスは下水道も本当に大きいんだね。すごいな。","ENG":"Speaking of which, even the sewers of Central Palace are huge. I’m impressed.","TWN":"不過，聖特羅貝里斯連下水道都好大喔，真是壯觀。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"너 겁쟁이야?","JPN":"あんた、弱虫？","ENG":"Are you a coward?","TWN":"你是膽小鬼嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"으, 응?","JPN":"え、うん？","ENG":"H-huh?","TWN":"呃…嗯？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"상대가 덤벼드는데 칼은 뽑지도 않고 도망만 다녔잖아?","JPN":"相手に襲われても剣も抜かずに逃げてばっかりだったじゃない？","ENG":"They were charging after you, but you didn’t even draw your sword and just ran.","TWN":"對方都已經撲上來了，你還不拔刀，只知道逃？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"피하느라 정신 없어서 꼴사납게 길바닥에 나동그라지기나 하고…….","JPN":"避けるのに精一杯で、ぶざまに道端に転んでみたり……","ENG":"You were also too busy avoiding them that you tripped sprawled over...!","TWN":"這樣倉皇逃跑，害我還在大街上狼狽地跌倒……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"미안. 하지만 어쩔 수 없었어. 알렌이 남들 앞에서 함부로 검을 뽑지 말라고 했거든.","JPN":"ごめん。でも仕方なかったんだ。他の人の前ではむやみに剣を抜くなって、アレンから言われてるから。","ENG":"Sorry, but I had no other choice. Allen told me not to draw my sword recklessly in front of others.","TWN":"抱歉，但我也無可奈何，因為艾倫叫我別輕易在人前亮刀。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그 알렌이란 사람이 네 아빠라도 돼?","JPN":"そのアレンって人、あんたのお父さん？","ENG":"Allen? Is he your dad or something?","TWN":"那的叫艾倫的人是你爸爸嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"아니, 친구야. 형제처럼 자랐던 친구.","JPN":"ううん、友達だよ。兄弟みたいに育った友達。","ENG":"No, he’s a friend. But we were raised like brothers.","TWN":"不是，我們是朋友，他就像我哥哥一樣。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그래? 그럼 그 사람이 죽으라고 하면 죽기라도 할 거야?","JPN":"ふうん？　じゃあ、その人が死ねって言ったら死ぬの？","ENG":"Is that right? So, if he tells you to die, are you going to die?","TWN":"喔，那他叫你去死的話你也會去死嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"예시가 조금 극단적이긴 한데…….","JPN":"例えがちょっと極端なんだけど……","ENG":"That’s a bit extreme, don’t you think...?","TWN":"你這個例子有點極端……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그래도 알렌이 그렇게 말할 정도라면 뭔가 이유가 있지 않을까?","JPN":"でも、アレンがそう言うくらいなら、何か訳があるんじゃないかな？","ENG":"But still, if Allen said something like that, there must be a reason, right?","TWN":"不過如果艾倫真的叫我去死，那應該也是有他的理由吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"이 멍청이가 계속 뭔 헛소릴 하는 거야!","JPN":"何ばかなこと言ってるのよ！","ENG":"Do you even hear the words coming out of your mouth, idiot?!","TWN":"你這個傻瓜在胡說八道什麼！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"방금 잡혔으면 우리 둘 다 꼼짝없이 죽었어.","JPN":"今さっき掴まっていたら、私たち二人とも否応なしに死んでたわ。","ENG":"If we had been captured just now, both of us would be dead.","TWN":"剛才要是被逮到的話，我們兩個肯定必死無疑！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"자기 목숨이 걸렸는데 싸워야 할지 말지는 직접 판단해야 하는 거 아냐?","JPN":"自分の命がかかっているのに、戦うかどうかは自分で判断するもんじゃないの？","ENG":"When your life is in danger, shouldn’t you be the one making the decision whether to fight or not?","TWN":"既然攸關自己的性命，那要不要出手，應該也是由自己判斷才對吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"난 절대로 남의 판단에 내 목숨을 걸지 않는다고!","JPN":"私は絶対、他人の判断に自分の命を委ねたりしないわ！","ENG":"I never put my life in the hands of others!","TWN":"我是絕對不會將我的性命交給別人來判斷的！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그런가……?","JPN":"そうかな……？","ENG":"I guess that makes sense...?","TWN":"是這樣嗎……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"칫……. 뭐 이렇게 한심한 인간이 다 있어.","JPN":"ちっ……こんなに情けない人がいるなんて。","ENG":"Tch... How can somebody be so pathetic?","TWN":"嘖……真是什麼莫名其妙的人都有！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"어디로 가려고?","JPN":"どこに行くの？","ENG":"Where are you going?","TWN":"你要去哪裡？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"네가 그걸 알아서 뭐 하려고?","JPN":"知ってどうするのよ？","ENG":"Why do you want to know?","TWN":"我去哪裡關你什麼事？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"어……. 그게, 일단은 네가 인질로 잡는 바람에 휘말렸으니까, 나도 알 권리는 있지 않을까?","JPN":"あ……それは、君が僕を人質にしたせいで巻き込まれちゃったから、知る権利くらいあるんじゃないかな？","ENG":"Um... Well, since I got caught up into all of this because you took me hostage, shouldn’t I have a right to know?","TWN":"呃……那個，因為你抓我當人質，現在我們算在同一條船上，那我應該有知的權利吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"흥, 권리는 무슨.","JPN":"ふん、何が権利よ。","ENG":"Hmph, you wish.","TWN":"哼，權利個鬼！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"얘기해 줘. 그러지 않으면 나는 네가 도둑질을 하고 도망친 노예라고 생각할 수밖에 없어.","JPN":"教えてよ。じゃなかったら、君のことを泥棒して逃げた奴隷だと思うしかない。","ENG":"Tell me. If you don’t, I have no choice but to think you’re a slave who ran away after stealing something.","TWN":"告訴我，否則我真的會認為你是行竊失風的奴隸。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"읏……?!","JPN":"うっ……！？","ENG":"H-huh...?!","TWN":"唔……？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"오해하지 말아 줘. 그냥 기사 분들이 서로 귓속말을 하는 걸 들었을 뿐이야.","JPN":"誤解しないで。騎士の人たちが耳うちしているのが聞こえただけだから。","ENG":"Don’t get me wrong. I merely heard what the knights were whispering to each other.","TWN":"別誤會，我只是湊巧聽到騎士們的談話。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"거짓말. 그 난장판 속에서 어떻게 귓속말을 들어.","JPN":"嘘つき。あの騒ぎの中でどうやって耳うちが聞こえるっていうの。","ENG":"Don’t lie. How could you hear whispering through all that commotion?","TWN":"你騙人！當時情況那麼混亂，你怎麼可能聽得到他們談話。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"진짜인데……. 믿어 주면 안 될까?","JPN":"嘘じゃないんだけど……信じてもらえないかな？","ENG":"I’m not lying... Can’t you trust me?","TWN":"是真的……你可以相信我嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"됐어. 어차피 옷차림을 보고 알아챈 거겠지.","JPN":"もういい。どうせ身なりを見てわかったんでしょ。","ENG":"Forget it. You probably figured it out after seeing what I’m wearing.","TWN":"不必了，你是從我的穿著發現的吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"왜 여기까지 따라왔는지 궁금했는데, 이제 알겠네.","JPN":"どうしてここまでついてきたのか気になってたけど、ようやく理解できたわ。","ENG":"I was wondering why you were following me all the way here... But now I get it.","TWN":"我還想說你為什麼要跟著我到這裡來，我現在知道原因了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"날 노예상에게 팔아서 한 몫 챙기려는 거지? 내가 순순히 팔려 줄 것 같아?","JPN":"私を奴隷商に売って稼ごうって腹でしょ？　素直に売られると思う？","ENG":"You’re trying to sell me to a slave merchant and make some money, aren’t you? Do you expect me to allow myself to be sold without a fight?","TWN":"你是想把我賣給奴隸商大撈一筆吧？你以為我會乖乖地束手就範嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"진정해. 나도 너랑 같이 죽을 뻔했잖아.","JPN":"落ち着いてよ。僕も君と一緒に死ぬところだったじゃないか。","ENG":"Calm down. I was almost killed too, remember?","TWN":"你冷靜點，我剛剛可是差點就和你一起喪命。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"내가 도와서 해결할 수 있는 문제라면 해결하고 싶어서 그래. 다른 뜻이 있는 건 아니야.","JPN":"僕で解決できる問題なら、手伝いたいだけなんだから。他意はないよ。","ENG":"I just want to help find a solution if I can. I don’t have any other intentions.","TWN":"我想看看我是否能幫上忙，我只是想幫你，沒別的意思。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"지금 그 말을 나더러 믿으라고?","JPN":"その言葉を信じろっていうの？","ENG":"So, I’m supposed to just take your word?","TWN":"你覺得我會相信你嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"방금 말한 것처럼…… 믿어 주면 안 될까?","JPN":"今言ったように……信じてもらえないかな？","ENG":"Like I said... Can’t you just trust me?","TWN":"就像我剛剛說的……你可以相信我嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"좋아. 네 말대로 나는 노예야.","JPN":"いいわ。そう、あんたの言うとおり、私は奴隷よ。","ENG":"Fine. As you said, I’m a slave.","TWN":"好吧，你說的沒錯，我是奴隸。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그리고 이 물건이……. 날 평민으로 만들어 줄 열쇠야.","JPN":"それからこれは……私を平民にしてくれる鍵なの。","ENG":"And this... This is my key to becoming a commoner.","TWN":"而這個東西……是可以把我變成普通平民的關鍵。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그 물건이……?","JPN":"その杖が……？","ENG":"That is...?","TWN":"那個東西……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그래, 나에게 일을 부탁한 사람이 약속했어.","JPN":"そう。仕事を依頼した人が約束してくれた。","ENG":"Yeah, I was promised by the person who asked me to steal this.","TWN":"沒錯，叫我做這件事的人有答應我，"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"이 물건을 가져다 주면 내 노예 증서를 없애 주겠다고.","JPN":"これを持っていけば私の奴隷証書をなかったことにしてくれるって。","ENG":"If I hand this to her, she said she’ll get rid of my slave certificate.","TWN":"只要將這個交給她，她就會幫我取消奴隸證。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"자, 이제 궁금한 건 다 풀렸어?","JPN":"さあ、もう疑問は解けた？","ENG":"So, are you done asking questions?","TWN":"怎麼樣？還有什麼想知道的嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"신분을 바꾸려고 목숨을 걸다니……. 노예가 그렇게 나쁜 거야?","JPN":"身分を変えるために命を懸けるなんて……奴隷ってそんなに酷いの？","ENG":"Risking your life to change your status... Is being a slave really that bad?","TWN":"奴隸有這麼糟糕嗎……讓你不惜賭上性命也要改變身分？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"너 지금 평민이라고 날 놀리는 거야? 노예가 그렇게 나쁜 거냐고?","JPN":"あんた、平民だからって私をばかにしてるの？　奴隷がそんなに酷いかって？","ENG":"Are you making fun of me for being a slave? \\"Is being a slave that bad?\\"","TWN":"你現在是用平民的身分再諷刺我嗎？奴隸有這麼糟糕嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"밥도, 물도 주인이 허락하지 않으면 먹지 못해! 자는 것도! 살아 있는 것도!","JPN":"ご飯も、水も、ご主人様が許可しなければ口にすることができない！　眠るのも！　生きることさえも！","ENG":"I can’t eat or drink without my master’s permission! Not even sleep! Not even live!","TWN":"不管是吃飯或喝水，沒有主人的允許，就不能吃喝！睡覺也是，生死也是！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"주인 기분이 더럽다고 등뼈가 부러지도록 채찍을 맞다가 죽어!","JPN":"ご主人様の気分が悪いからって、背骨が折れるくらい鞭打たれて死ぬ！","ENG":"I could die under the whip just because my master is in a bad mood!","TWN":"主人只要心情不好，就會拿鞭子狂抽，抽到你沒命為止！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"남자 노예랑 손을 잡았다고 산 채로 불에 타서 죽어!","JPN":"男の奴隷と手を繋いだといって、生きたまま焼かれて死ぬ！","ENG":"I could be burned alive just for holding the hand of a slave boy!","TWN":"和男的奴隸牽手，就把你活活燒死！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"우린 사람을 닮은 가축이야!","JPN":"奴隷は人の姿をした家畜よ！","ENG":"We’re merely cattle who look like people!","TWN":"我們跟畜生有什麼兩樣！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"물론 제국법이 인간으로 대접해 주는 평민님께서는 죽었다 깨어나도 모르시겠지!","JPN":"もちろん帝国法で人間として扱ってもらえる平民様には死んでもわからないでしょうけど！","ENG":"Of course, a commoner like you who’s treated as a human being under imperial law will never know what it’s like being a slave!","TWN":"像你這種受帝國法保護的平民，就算再投胎一次也不會懂吧！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"우리 할아버지는 언젠가 구원자님이 우릴 해방시켜줄 거라는 말만 평생 믿다가 죽어 버렸어.","JPN":"お爺さんは、いつか救世主が私たちを解放してくれるっていう言葉を一生信じて死んでいった。","ENG":"My grandfather died after believing all his life that the Savior would one day free us all.","TWN":"我爺爺到死前都一直深信，總有一天救贖者會釋放我們。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"……어차피 주인들이 노예 관리를 쉽게 하려고 퍼뜨린 헛소리였을 텐데.","JPN":"……どうせ主人どもが奴隷を管理しやすくするために広めた、くだらないデマだろうに。","ENG":"...That’s probably a rumor spread by slave masters to make us easier to control.","TWN":"……我看這只是主人為了方便管理奴隸，而捏造的謊言吧！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"구원자 따위 제국 입맛대로 정하는 거잖아? 그런 놈이 노예들을 해방시킨다고?","JPN":"救世主なんて帝国の好みで決めるものじゃない？　そんなやつが奴隷を解放してくれるって？","ENG":"The Savior is chosen by the Empire, right? That kind of person is going to free slaves?","TWN":"所謂的救贖者根本是帝國的走狗吧？那種傢伙會釋放奴隸？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"나는…… 내 손으로 날 구원할 거야. 내 손에 쥐고 있는 <color=#ffd34c>이걸</color>로.","JPN":"私は……私の手で自分を救うの。今手にある<color=#ffd34c>これ</color>で。","ENG":"I’ll... I'll save myself with my own hands. Using <color=#ffd34c>this</color>.","TWN":"我……要親手救贖我自己，就用我手裡拿著的<color=#ffd34c>這個</color>！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"후우, 실컷 소리쳤더니 한결 나아졌어.","JPN":"ふぅ、思いっきり叫んだらだいぶ落ち着いたわ。","ENG":"Whew... I feel much better after making such a fuss.","TWN":"呼～吼出來後心裡舒坦多了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"뭐 해? 멀뚱거리지 말고 빨리 따라와.","JPN":"何してるの？　ぼんやりしてないで、早くついてきて。","ENG":"What are you doing? Don’t just stand there like an idiot and follow me quickly.","TWN":"傻楞著幹嘛？快跟我來！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"어? 같이 다니기 싫은 거 아니었어?","JPN":"え？　一緒に行きたくなかったんじゃないの？","ENG":"Huh? Didn’t you say that you didn’t want me to go with you?","TWN":"嗯？你不是不喜歡我跟著你嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"당연하지. 멍청하고 겁쟁이인 데다가 소심한 인간이 좋을 리 없잖아.","JPN":"当たり前でしょ。ばかで弱虫な上に小心な人がいいわけないじゃない。","ENG":"Of course I don’t. You’re cowardly, stupid and timid. There’s no way that I’d be happy with you tagging along.","TWN":"是不喜歡，誰會喜歡一個愚蠢、膽小，又婆媽的人？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"우으…… 알렌이 잔소리가 심하다고 생각했는데 아닌 것 같아…….","JPN":"うう……アレンは小言が酷いと思ってたけど、そうでもなかったみたいだ……","ENG":"Oof... And I thought Allen’s scolding was bad, but this is worse...","TWN":"呃……我還以為艾倫已經夠多話了，沒想到一山還有一山高……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"싫긴 하지만 어쨌거나 네 덕분에 기사들에게서 달아날 수 있었던 건 사실이니까.","JPN":"嫌だけど、あんたのおかげで騎士から逃げおおせたのは事実だから。","ENG":"I don’t like you, but it is a fact that I was able to get away from those knights thanks to you.","TWN":"我是不喜歡，但再怎麼說，你剛確實是幫我甩掉那些騎士。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"의뢰인에게 날 도와 줬다고 말해 줄게. 그럼 은전 몇 푼 정도는 하사해 줄지도 몰라.","JPN":"依頼人に助けてもらったって言ってあげるわ。そうしたらお礼にいくらかぐらいはもらえるかもね。","ENG":"I’ll tell my contact that you helped me. Who knows, maybe you’ll be able to receive a few silver coins.","TWN":"我會跟委託人說你有幫我，或許她會賞你點銀子。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"괜찮을까……. 알렌이 걱정하고 있을 텐데.","JPN":"大丈夫かな……アレンが心配してると思うけど。","ENG":"I don’t know... Allen will be worried about me.","TWN":"這樣沒關係嗎……艾倫應該會擔心吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};